  1→import {
  2→  checkout,
  3→  dodopayments,
  4→  portal,
  5→} from "@dodopayments/better-auth";
  6→import { drizzleAdapter } from "better-auth/adapters/drizzle";
  7→import { betterAuth } from "better-auth/minimal";
  8→import { env as clientEnv } from "@/env/client";
  9→import { env as serverEnv } from "@/env/server";
 10→import { db } from "@/server/db";
 11→import * as schema from "@/server/db/models/auth.model";
 12→import { BILLING_CONFIG } from "./billing-config";
 13→import { dodo } from "./dodo";
 14→import { resend } from "./resend";
 15→
 16→export const auth = betterAuth({
 17→  baseURL: clientEnv.NEXT_PUBLIC_SERVER_URL || "http://localhost:3000",
 18→  session: {
 19→    cookieCache: {
 20→      enabled: true,
 21→      maxAge: 5 * 60, // 5 minutes
 22→    },
 23→  },
 24→  database: drizzleAdapter(db, {
 25→    provider: "pg",
 26→    schema,
 27→  }),
 28→  databaseHooks: {
 29→    user: {
 30→      create: {
 31→        before: async (user) => {
 32→          if (serverEnv.ENABLE_SIGNUPS !== "true") {
 33→            throw new Error(
 34→              "Signups are currently disabled. Please join the waitlist.",
 35→            );
 36→          }
 37→          return { data: user };
 38→        },
 39→      },
 40→    },
 41→  },
 42→  trustedOrigins: [clientEnv.NEXT_PUBLIC_SERVER_URL],
 43→  emailAndPassword: {
 44→    enabled: true,
 45→    async sendResetPassword({ user, url }) {
 46→      await resend.emails.send({
 47→        from: `RunAgents Auth <hello@${serverEnv.EMAIL_DOMAIN}>`,
 48→        to: user.email,
 49→        subject: "Reset your password",
 50→        text: `Click the link to reset your password: ${url}`,
 51→      });
 52→    },
 53→  },
 54→  socialProviders: {
 55→    google: {
 56→      clientId: serverEnv.GOOGLE_CLIENT_ID,
 57→      clientSecret: serverEnv.GOOGLE_CLIENT_SECRET,
 58→      enabled: !!(serverEnv.GOOGLE_CLIENT_ID && serverEnv.GOOGLE_CLIENT_SECRET),
 59→    },
 60→  },
 61→  emailVerification: {
 62→    async sendVerificationEmail({ user, url }) {
 63→      await resend.emails.send({
 64→        from: `RunAgents Auth <hello@${serverEnv.EMAIL_DOMAIN}>`,
 65→        to: user.email,
 66→        subject: "Verify your email address",
 67→        text: `Click the link to verify your email: ${url}`,
 68→      });
 69→    },
 70→  },
 71→  user: {
 72→    additionalFields: {
 73→      trialExpiresAt: {
 74→        type: "date",
 75→        defaultValue: () =>
 76→          new Date(
 77→            Date.now() + BILLING_CONFIG.trialDays * 24 * 60 * 60 * 1000,
 78→          ),
 79→        input: false,
 80→      },
 81→    },
 82→  },
 83→  plugins: [
 84→    dodopayments({
 85→      client: dodo,
 86→      createCustomerOnSignUp: true,
 87→      use: [
 88→        checkout({
 89→          products: Object.values(BILLING_CONFIG.plans).map((p) => ({
 90→            productId: p.productId,
 91→            slug: p.slug,
 92→          })),
 93→          successUrl: "/billing/return",
 94→          authenticatedUsersOnly: true,
 95→        }),
 96→        portal(),
 97→      ],
 98→    }),
 99→  ],
100→});
