 9→const joinWaitlistSchema = z.object({
10→  email: z.string().email(),
11→});
12→
13→export async function joinWaitlistAction(email: string) {
14→  const parsed = joinWaitlistSchema.safeParse({ email });
15→  if (!parsed.success) {
16→    throw new Error("Invalid email address.");
17→  }
18→
19→  try {
20→    await waitlistRepo.insertEmail(parsed.data.email);
21→
22→    void resend.emails.send({
23→      from: `RunAgents <hello@${env.EMAIL_DOMAIN}>`,
24→      to: parsed.data.email,
25→      subject: "You're on the list!",
26→      react: WaitlistEmail({ email: parsed.data.email }),
27→    });
28→
29→    return { success: true };
30→  } catch (error) {
31→    console.error("Failed to join waitlist:", error);
32→    throw new Error("Failed to join waitlist. Please try again later.");
33→  }
34→}
