 27→export const createSandbox = authedAction(
 28→  z.object({
 29→    name: z.string().min(1, "Name is required").max(50, "Name is too long"),
 30→    telegramBotToken: z
 31→      .string()
 32→      .regex(/^\d+:[A-Za-z0-9_-]+$/, "Invalid bot token format"),
 33→  }),
 34→  async ({ user }, input) => {
 35→    const openrouterApiKey = env.OPENROUTER_API_KEY;
 36→    if (!openrouterApiKey)
 37→      throw new Error("OPENROUTER_API_KEY is not configured");
 38→
 39→    const runtime = await Sandbox.betaCreate(E2B_TEMPLATE_NAME, {
 40→      apiKey: getE2BApiKey(),
 41→      autoPause: true,
 42→      timeoutMs: E2B_TIMEOUT_MS,
 43→      metadata: { userId: user.id, name: input.name },
 44→    });
 45→
 46→    try {
 47→      await runOrThrow(
 48→        runtime,
 49→        `${OPENCLAW_BIN} onboard \
 50→        --non-interactive --accept-risk \
 51→        --flow quickstart \
 52→        --gateway-bind loopback --gateway-auth token \
 53→        --skip-health \
 54→        --auth-choice openrouter-api-key \
 55→        --openrouter-api-key "${openrouterApiKey}"`,
 56→        "Credential injection",
 57→      );
 58→
 59→      await runOrThrow(
 60→        runtime,
 61→        `jq --arg model "${OPENCLAW_MODEL}" --arg alias "${OPENCLAW_MODEL_ALIAS}" --arg botToken "${input.telegramBotToken}" '
 62→          .agents.defaults.model.primary = $model |
 63→          .agents.defaults.models[$model] = {"alias": $alias} |
 64→          .plugins.entries.telegram.enabled = true |
 65→          .channels.telegram.enabled = true |
 66→          .channels.telegram.botToken = $botToken
 67→        ' ~/.openclaw/openclaw.json > /tmp/openclaw.json && mv /tmp/openclaw.json ~/.openclaw/openclaw.json`,
 68→        "Config patch",
 69→      );
 70→
 71→      await runOrThrow(
 72→        runtime,
 73→        `nohup ${OPENCLAW_BIN} gateway run > /tmp/gateway.log 2>&1 &`,
 74→        "Gateway start",
 75→      );
 76→
 77→      const info = await runtime.getInfo({ requestTimeoutMs: 15_000 });
 78→
 79→      return await sandboxRepo.create({
 80→        userId: user.id,
 81→        name: input.name,
 82→        e2bSandboxId: runtime.sandboxId,
 83→        e2bTemplateId: info.templateId,
 84→        telegramBotToken: input.telegramBotToken,
 85→        deploymentStatus: "running",
 86→      });
 87→    } catch (error) {
 88→      await runtime.kill().catch(() => undefined);
 89→      throw error;
 90→    }
 91→  },
 92→);
