 94→export const deleteSandbox = authedAction(
 95→  z.object({ sandboxId: z.string().min(1) }),
 96→  async ({ user }, input) => {
 97→    const sandbox = await sandboxRepo.findById(input.sandboxId, user.id);
 98→    if (!sandbox) throw new Error("Sandbox not found");
 99→
100→    if (sandbox.e2bSandboxId) {
101→      const runtime = await connectSandbox(sandbox.e2bSandboxId).catch(
102→        () => null,
103→      );
104→      await runtime?.kill().catch(() => undefined);
105→    }
106→
107→    await sandboxRepo.deleteById(input.sandboxId, user.id);
108→  },
109→);
